var UserConnection = Get<UserConnection>("UserConnection");
var SubmissionId = Get<Guid>("SubmissionId");
var LineDetailId = Get<Guid>("LineDetailId");
var StringParam = Get<string>("StringParam");

try {
	var service = new CreateCustomerSalesOrderUERPService(UserConnection);
	if(!string.IsNullOrEmpty(StringParam) && SubmissionId == Guid.Empty && LineDetailId == Guid.Empty) {
		
		service.SetParam(StringParam);
		
	} else if(string.IsNullOrEmpty(StringParam) && SubmissionId != Guid.Empty && LineDetailId == Guid.Empty) {
		
		service.SetParamBySubmission(SubmissionId);
		
	} else if(string.IsNullOrEmpty(StringParam) && SubmissionId == Guid.Empty && LineDetailId != Guid.Empty) {
		
		service.SetParamByLineDetail(LineDetailId);
		
	} else {
		throw new Exception("Input param harus diisi salah satunya");
	}

	Set("BuildParam", service.GetStringRequest());

	service.Request().GetAwaiter().GetResult();
	if(!service.IsSuccessResponse()) {
		throw new Exception(service.GetErrorResponse());
	}
	
	Set("Response", service.GetStringResponse());
} catch(Exception e) {
	Set("Message", e.Message);
}

return true;
